#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m;
    cin>>n>>m;
    int b,c,d,e;
    cin>>b>>c>>d>>e;
    string a[n][m],z;
    for(int i=0;i<n;i++){
        cin>>z;
        for(int j=0;j<m;j++){
            a[i][j]=z[j];
        }
    }
    for(int i=b-1;i<c;i++){
        for(int j=d-1;j<e;j++){
            cout<<a[i][j];
        }
        cout<<endl;
    }
    return 0;
}
